// Question bank and subtopic definitions for the interview lab.
// Each topic has subtopics with keywords for transcript matching and a bank
// of sample questions the system instruction can reference.
//
// Kept framework-free so both the client page and the server report route
// can import it.

export interface Subtopic {
  id: string
  label: string
  /** Keywords used to detect coverage in the transcript post-interview. */
  keywords: string[]
}

export interface BankQuestion {
  subtopicId: string
  text: string
  difficulty: 'easy' | 'medium' | 'expert'
  answer: string
}

export interface TopicSubtopics {
  topicId: string
  subtopics: Subtopic[]
  questions: BankQuestion[]
}

// ── HTML ────────────────────────────────────────────────────────────────────

const HTML_SUBTOPICS: TopicSubtopics = {
  topicId: 'html',
  subtopics: [
    { id: 'semantics', label: 'Semantic Elements', keywords: ['semantic', 'article', 'section', 'header', 'footer', 'nav', 'main', 'aside', 'landmark'] },
    { id: 'forms', label: 'Forms & Validation', keywords: ['form', 'input', 'select', 'textarea', 'validation', 'required', 'pattern', 'constraint'] },
    { id: 'accessibility', label: 'Accessibility (a11y)', keywords: ['accessibility', 'aria', 'role', 'alt', 'screen reader', 'tabindex', 'wcag', 'a11y', 'label'] },
    { id: 'document-outline', label: 'Document Structure', keywords: ['document', 'head', 'meta', 'doctype', 'charset', 'viewport', 'headings', 'outline'] },
    { id: 'media', label: 'Media & Embedding', keywords: ['video', 'audio', 'canvas', 'svg', 'iframe', 'embed', 'picture', 'source', 'srcset'] },
    { id: 'seo', label: 'SEO & Meta', keywords: ['seo', 'meta', 'open graph', 'og:', 'twitter card', 'canonical', 'sitemap', 'structured data'] },
  ],
  questions: [
    { subtopicId: 'semantics', text: 'Why would you choose an article element over a div for a blog post?', difficulty: 'easy', answer: 'An article element conveys self-contained, independently distributable content, giving it an implicit ARIA role of article. Screen readers can announce it as a distinct region, and search engines treat it as syndicatable content, whereas a div carries no semantic meaning.' },
    { subtopicId: 'semantics', text: 'What landmarks does the browser infer from semantic elements, and why does that matter for assistive tech?', difficulty: 'medium', answer: 'Elements like main, nav, header, footer, aside, and section (with an accessible name) map to ARIA landmark roles. Screen reader users rely on these landmarks to navigate the page structure quickly via shortcut keys, so using semantic elements gives them a navigable outline without any extra ARIA attributes.' },
    { subtopicId: 'semantics', text: 'When would you use the details and summary elements instead of a custom accordion?', difficulty: 'easy', answer: 'Use details/summary for simple toggle-to-reveal sections because they provide native open/close behavior, keyboard accessibility, and the summary element is focusable by default. A custom accordion is warranted when you need animation, exclusive-open (one-at-a-time) semantics, or complex ARIA patterns that the native elements cannot express.' },
    { subtopicId: 'semantics', text: 'How does the browser determine the implicit ARIA roles of elements like nav, aside, and main?', difficulty: 'medium', answer: 'The HTML-AAM (HTML Accessibility API Mappings) specification defines which role each native element maps to. For example, nav maps to navigation, aside to complementary, and main to main. These mappings are hardcoded in the browser\'s accessibility tree and do not require explicit role attributes.' },
    { subtopicId: 'forms', text: 'What built-in validation attributes does HTML provide, and when would you use pattern instead?', difficulty: 'easy', answer: 'HTML provides required, min, max, minLength, maxLength, type, and step for constraint validation. Use the pattern attribute with a regular expression when the built-in constraints are insufficient, such as validating a custom format like a postal code or an alphanumeric product key.' },
    { subtopicId: 'forms', text: 'How does the browser decide which element gets focus when a user presses Tab inside a complex form?', difficulty: 'expert', answer: 'Focus follows DOM order by default, skipping elements with tabindex="-1". A positive tabindex inserts the element into a numbered focus sequence, but this is discouraged because it creates an unpredictable order. In practice, ensuring a logical DOM order and using tabindex="0" or "−1" on custom interactive elements is the reliable approach.' },
    { subtopicId: 'forms', text: 'Explain the difference between the validity and checkValidity APIs on form elements.', difficulty: 'medium', answer: 'validity is a read-only ValidityState object that exposes individual boolean flags like valueMissing and patternMismatch. checkValidity() runs the full constraint validation algorithm on the element, triggers an invalid event if validation fails, and returns true or false. Use validity to inspect why a field failed; use checkValidity to programmatically trigger validation.' },
    { subtopicId: 'forms', text: 'When would you use the datalist element versus a custom autocomplete implementation?', difficulty: 'medium', answer: 'Use a datalist when you need a simple dropdown of suggestions that the user may or may not accept, with zero JavaScript required. A custom autocomplete is necessary when you need debounced server-side lookups, grouped results, keyboard-navigable virtual lists, or full control over the suggestion markup and selection behavior.' },
    { subtopicId: 'accessibility', text: 'When should you use aria-label versus a visually-hidden text span?', difficulty: 'medium', answer: 'Use aria-label when the element has no visible text and you need to provide an accessible name, such as on an icon-only button. Use a visually-hidden span when the label should be present in the DOM for screen readers but visually hidden with CSS, which is useful when you need the text to be available for testing or translation tools.' },
    { subtopicId: 'accessibility', text: 'Explain the difference between role="button" and a native button element from an accessibility standpoint.', difficulty: 'medium', answer: 'A native button element comes with built-in keyboard support (Enter and Space activation), focus management, and participates in the implicit label calculation. role="button" on a div only exposes the button role in the accessibility tree but requires you to manually implement keyboard event handling, focus styling, and proper labeling.' },
    { subtopicId: 'accessibility', text: 'What are ARIA live regions and when would you use aria-live="polite" versus "assertive"?', difficulty: 'expert', answer: 'Live regions let you announce dynamic content changes to screen readers without moving focus. Use polite (the default) for non-urgent updates like a word count change, which waits until the user is idle. Use assertive for critical alerts like form validation errors, which interrupt the user immediately — but use it sparingly to avoid overwhelming the user.' },
    { subtopicId: 'document-outline', text: 'Why was the h1-per-section model abandoned in the HTML5 spec, and what do browsers actually do?', difficulty: 'expert', answer: 'The HTML5 spec originally proposed an algorithmic document outline based on section/article nesting that allowed every section to use h1. Browsers never implemented this algorithm and instead preserve the flat heading hierarchy. Consequently, most screen readers and SEO tools still rely on the traditional h1–h6 nesting for the document outline.' },
    { subtopicId: 'document-outline', text: 'What is the purpose of the meta viewport element and how does it affect mobile rendering?', difficulty: 'easy', answer: 'The meta viewport element tells the browser to set the initial viewport width to the device width and the initial scale to 1, preventing the mobile browser from zooming out to fit a desktop-width layout. Without it, mobile browsers assume a ~980px viewport and scale the page down, making content unreadable.' },
    { subtopicId: 'media', text: 'What is the purpose of the picture element and srcset attribute?', difficulty: 'easy', answer: 'The picture element enables art direction by letting you provide different image sources for different viewport sizes or pixel densities using media queries inside source elements. The srcset attribute on an img element handles resolution switching, letting the browser pick the best image file based on viewport size and device pixel ratio without changing the displayed dimensions.' },
    { subtopicId: 'media', text: 'How does lazy loading with the loading attribute work, and when would you use eager instead?', difficulty: 'medium', answer: 'When loading="lazy" is set, the browser defers fetching the image until it is near the viewport, determined by the browser\'s own heuristic (typically a few hundred pixels). Use loading="eager" for above-the-fold images like hero banners or logos, where delaying the load would harm the Largest Contentful Paint metric.' },
    { subtopicId: 'media', text: 'What are the trade-offs between using an iframe versus the embed element for third-party content?', difficulty: 'medium', answer: 'An iframe provides a fully sandboxed browsing context with robust isolation, and the sandbox attribute lets you restrict permissions. An embed element is simpler but runs in the same browsing context, so it has weaker security boundaries. Use iframes for untrusted third-party content and embed for plugins or simple widget-like content that you control.' },
    { subtopicId: 'seo', text: 'What meta tags are essential for a page to render well on mobile and share correctly on social media?', difficulty: 'medium', answer: 'You need the meta viewport tag with width=device-width, initial-scale=1 for correct mobile rendering. For social sharing, include og:title, og:description, og:image, and og:url for Open Graph, plus twitter:card, twitter:title, twitter:description, and twitter:image. A descriptive title tag and meta description are also essential for search engines.' },
    { subtopicId: 'seo', text: 'How does structured data (JSON-LD) help search engines understand your content?', difficulty: 'medium', answer: 'JSON-LD embeds machine-readable schema.org data directly in the page, letting search engines identify the content type (Article, Product, FAQ, etc.) and display rich results like stars, prices, or FAQ accordions in search listings. It is preferred over microdata because it is kept in a single script block and does not require wrapping HTML attributes around content.' },
  ],
}

// ── CSS ─────────────────────────────────────────────────────────────────────

const CSS_SUBTOPICS: TopicSubtopics = {
  topicId: 'css',
  subtopics: [
    { id: 'flexbox', label: 'Flexbox', keywords: ['flexbox', 'flex', 'display: flex', 'justify-content', 'align-items', 'flex-direction', 'gap', 'flex-wrap'] },
    { id: 'grid', label: 'CSS Grid', keywords: ['grid', 'display: grid', 'grid-template', 'grid-area', 'grid-column', 'fr', 'auto-fit', 'auto-fill'] },
    { id: 'specificity', label: 'Specificity & Cascade', keywords: ['specificity', 'cascade', 'inheritance', 'layer', '@layer', 'important', 'selector'] },
    { id: 'responsive', label: 'Responsive Design', keywords: ['responsive', 'media query', 'breakpoint', 'mobile-first', 'container query', 'clamp'] },
    { id: 'layout', label: 'Layout & Positioning', keywords: ['position', 'float', 'display', 'overflow', 'box model', 'margin collapse', 'sticky', 'relative', 'absolute', 'fixed'] },
    { id: 'animations', label: 'Animations & Transitions', keywords: ['transition', 'animation', 'keyframe', 'transform', 'ease', 'duration', 'will-change'] },
  ],
  questions: [
    { subtopicId: 'flexbox', text: 'When would you use flex-wrap instead of letting items shrink with flex-shrink?', difficulty: 'easy', answer: 'Use flex-wrap when items should stay at their natural size and wrap onto new lines rather than compressing. flex-shrink squishes items below their content width to fit a single line, which can distort content. Wrapping preserves each item\'s intrinsic size and is better for flows like tag lists or card grids.' },
    { subtopicId: 'flexbox', text: 'How does the browser resolve conflicting align-items and alignSelf on the same element?', difficulty: 'medium', answer: 'align-self always overrides align-items on the individual flex item because it is the per-item override of the container\'s cross-axis alignment. align-items sets a default for all children, while align-self lets any child opt out of that default.' },
    { subtopicId: 'flexbox', text: 'What is the difference between flex-grow on a child and align-self on the same child?', difficulty: 'medium', answer: 'flex-grow controls how much extra space along the main axis a child absorbs relative to its siblings. align-self controls the child\'s position along the cross axis, overriding the container\'s align-items. They operate on perpendicular axes and solve completely different layout problems.' },
    { subtopicId: 'flexbox', text: 'How would you build a holy grail layout using only flexbox?', difficulty: 'medium', answer: 'Create a flex column container with three children: header, a flex row body, and footer. The body row contains a fixed-width sidebar, a flex-grow: 1 main content area, and an optional right sidebar. Set min-height: 100vh on the outer container and use flex-shrink: 0 on the header and footer so they never collapse.' },
    { subtopicId: 'grid', text: 'Explain the difference between auto-fit and auto-fill in repeat(). When would you choose one over the other?', difficulty: 'medium', answer: 'Both create as many tracks as will fit, but auto-fit collapses empty tracks to zero width while auto-fill preserves them. Use auto-fill when you want placeholder tracks to maintain spacing even when empty, and auto-fit when you want items to stretch and fill the full available width when fewer items exist than tracks.' },
    { subtopicId: 'grid', text: 'How does implicit grid row creation work, and how can you control the track size with grid-auto-rows?', difficulty: 'medium', answer: 'When an item is placed outside the explicitly defined grid, the browser auto-creates implicit tracks to accommodate it. grid-auto-rows sets the size of these implicit rows, accepting values like 100px, 1fr, or minmax() to control their height instead of relying on content-based sizing.' },
    { subtopicId: 'grid', text: 'When would you use named grid areas versus line-based placement?', difficulty: 'easy', answer: 'Named grid areas (grid-template-areas) are ideal when you want a readable, visual map of your layout that non-technical stakeholders can understand. Line-based placement is better for dynamic or programmatic layouts where column/row indices change frequently or when you need precise control over spanning across specific track lines.' },
    { subtopicId: 'grid', text: 'How do you create a responsive card layout that switches from 1 column on mobile to 4 on desktop without media queries?', difficulty: 'expert', answer: 'Use grid-template-columns: repeat(auto-fit, minmax(min(250px, 100%), 1fr)). The minmax with min() ensures each card is at least 250px but never wider than the container, and auto-fit automatically adjusts the number of columns based on available space. No media queries are needed because the track sizing is inherently fluid.' },
    { subtopicId: 'specificity', text: 'How does CSS layer (@layer) interact with specificity in CSS3?', difficulty: 'expert', answer: 'Rules in later-declared layers always win over earlier layers regardless of selector specificity. Within a single layer, normal specificity rules apply. Unlayered styles always beat layered styles, giving authors a way to override everything. @layer lets you explicitly control cascade ordering independent of specificity.' },
    { subtopicId: 'specificity', text: 'If a utility class and a component class both set color, which one wins and why?', difficulty: 'medium', answer: 'Whichever class is declared later in the stylesheet wins when specificity is equal, following the cascade order. If they have the same specificity, the source order determines the winner. Utility frameworks like Tailwind often use !important or higher-specificity selectors to guarantee utilities override component styles.' },
    { subtopicId: 'specificity', text: 'What is the specificity of :is() and :has() pseudo-class selectors?', difficulty: 'expert', answer: ':is() takes the specificity of its most specific argument, ignoring the pseudo-class itself. :has() works the same way — its specificity is the specificity of its most specific selector argument. Neither pseudo-class adds its own specificity weight; they simply pass through the specificity of what\'s inside them.' },
    { subtopicId: 'responsive', text: 'What is the mobile-first approach and why is it preferred over desktop-first media queries?', difficulty: 'easy', answer: 'Mobile-first means writing base styles for small screens and using min-width media queries to add complexity for larger ones. It is preferred because mobile devices have constrained resources and bandwidth, so starting with a lean base ensures faster loads. It also produces simpler, more maintainable CSS with fewer overrides.' },
    { subtopicId: 'responsive', text: 'How do container queries differ from media queries, and when would you use each?', difficulty: 'medium', answer: 'Media queries respond to the viewport size, while container queries respond to the size of a parent container element. Use container queries when a component needs to adapt based on where it\'s placed rather than the screen width, such as a card that should stack vertically in a sidebar but lay out horizontally in a full-width section.' },
    { subtopicId: 'responsive', text: 'Explain the clamp() function and how it replaces min/max media queries for fluid typography.', difficulty: 'medium', answer: 'clamp(minimum, preferred, maximum) constrains a value between a floor and ceiling while the preferred value scales fluidly between them. For typography, clamp(1rem, 2.5vw, 2rem) replaces multiple media queries by smoothly interpolating font-size from 1rem at small viewports to 2rem at large ones, with no breakpoint jumps.' },
    { subtopicId: 'layout', text: 'When would you use position sticky versus a JavaScript-based scroll observer?', difficulty: 'medium', answer: 'Use position sticky for simple "stick to top" behavior like table headers or navigation bars because it runs on the compositor thread and is jank-free. Use a JavaScript scroll observer when you need to trigger actions at specific scroll positions, animate elements in/out of view, or handle complex conditions that CSS alone cannot express.' },
    { subtopicId: 'layout', text: 'How does margin collapse work, and when does it NOT happen?', difficulty: 'medium', answer: 'Vertical margins between adjacent block elements collapse to the larger of the two values instead of adding together. This does not happen in flex or grid containers, between floated elements, between elements with inline formatting contexts, or when border or padding separates the margins. It also does not occur with horizontal margins.' },
    { subtopicId: 'layout', text: 'What is the difference between overflow: hidden and overflow: clip?', difficulty: 'expert', answer: 'overflow: hidden creates a new block formatting context, which can affect layout by containing floats and influencing margin collapsing behavior. overflow: clip simply clips content at the element\'s border box without establishing a new formatting context, making it a lighter-weight option when you only need visual clipping without layout side effects.' },
    { subtopicId: 'animations', text: 'What does will-change do, and why should you use it sparingly?', difficulty: 'medium', answer: 'will-change hints to the browser that an element will be animated, prompting it to promote the element to its own compositor layer for smoother performance. Overusing it wastes GPU memory because each promoted layer consumes VRAM, and too many layers can actually hurt performance by increasing compositing overhead and memory pressure.' },
    { subtopicId: 'animations', text: 'How do you decide between CSS transitions and the Web Animations API for a complex UI effect?', difficulty: 'expert', answer: 'Use CSS transitions for simple state-based animations like hover effects where the browser can optimize the compositor path. Use the Web Animations API when you need fine-grained timeline control, dynamic keyframe manipulation, play/pause/reverse APIs, or complex sequencing that CSS alone cannot express without JavaScript intervention.' },
    { subtopicId: 'animations', text: 'What is the difference between transform and translate for positioning elements?', difficulty: 'easy', answer: 'transform: translate(x, y) moves an element visually without affecting document flow or triggering layout recalculation. translate as a standalone CSS property (e.g., translate: 10px 20px) does the same visually but participates in the element\'s layout box, which can affect stacking context and overflow calculations differently than the transform version.' },
  ],
}

// ── JavaScript ──────────────────────────────────────────────────────────────

const JS_SUBTOPICS: TopicSubtopics = {
  topicId: 'javascript',
  subtopics: [
    { id: 'closures', label: 'Closures & Scope', keywords: ['closure', 'lexical', 'scope', 'inner function', 'outer function', 'variable capture'] },
    { id: 'event-loop', label: 'Event Loop & Concurrency', keywords: ['event loop', 'callback', 'macro task', 'micro task', 'promise', 'queue', 'stack', 'settimeout', 'setimmediate'] },
    { id: 'prototypes', label: 'Prototypes & OOP', keywords: ['prototype', '__proto__', 'class', 'extends', 'inheritance', 'object.create', 'method'] },
    { id: 'async', label: 'Async Patterns', keywords: ['async', 'await', 'promise', 'then', 'catch', 'finally', 'concurrent', 'parallel', 'race'] },
    { id: 'modules', label: 'Modules', keywords: ['import', 'export', 'module', 'require', 'commonjs', 'esm', 'dynamic import'] },
    { id: 'error-handling', label: 'Error Handling', keywords: ['error', 'try', 'catch', 'throw', 'finally', 'typeerror', 'referenceerror', 'custom error'] },
    { id: 'types-coercion', label: 'Types & Coercion', keywords: ['type', 'coercion', 'equality', 'typeof', 'instanceof', 'truthy', 'falsy', 'nan'] },
  ],
  questions: [
    { subtopicId: 'closures', text: 'Explain what a closure is and give a real-world use case.', difficulty: 'easy', answer: 'A closure is a function that retains access to its lexical scope even after the outer function has returned. Practical uses include data privacy (hiding variables from global scope), function factories, and event handlers that need to remember state from when they were created.' },
    { subtopicId: 'closures', text: 'How does the classic var-in-a-loop problem demonstrate closure behavior, and how do you fix it?', difficulty: 'medium', answer: 'When var is used in a for-loop, all iterations share the same function-scoped variable, so callbacks formed by closures all see the final value. Switching to let creates a new binding per iteration, giving each closure its own copy. Alternatively, wrapping the loop body in an IIFE or passing the index as a parameter achieves the same effect.' },
    { subtopicId: 'closures', text: 'What is the module pattern and how does it leverage closures for private state?', difficulty: 'medium', answer: 'The module pattern uses an IIFE or module scope to return an object of public methods that close over private variables defined in the enclosing scope. Because the private variables are not on the returned object, they cannot be accessed or mutated from outside, providing encapsulation without class-based privacy modifiers.' },
    { subtopicId: 'event-loop', text: 'What is the difference between microtasks and macrotasks? Give examples of each.', difficulty: 'medium', answer: 'Microtasks (e.g. Promise callbacks, queueMicrotask, MutationObserver) are processed after the current synchronous task completes but before the next macrotask. Macrotasks (e.g. setTimeout, setInterval, I/O, message events) are scheduled one at a time in the task queue. The browser runs all microtasks to completion between each macrotask.' },
    { subtopicId: 'event-loop', text: 'Why does console.log(1); setTimeout(() => console.log(2)); Promise.resolve().then(() => console.log(3)) print 1, 3, 2?', difficulty: 'medium', answer: 'console.log(1) executes synchronously first. The Promise.then callback is a microtask, so it runs immediately after the current synchronous code finishes, printing 3. setTimeout schedules a macrotask, which only runs after the microtask queue is drained, printing 2 last.' },
    { subtopicId: 'event-loop', text: 'How does requestAnimationFrame differ from setTimeout for scheduling work?', difficulty: 'medium', answer: 'requestAnimationFrame fires before the browser paints, synchronised with the display refresh rate (~16ms at 60Hz), making it ideal for smooth animations. setTimeout has a minimum delay (typically 4ms) and is not synced to the paint cycle, so visual updates may cause jank or be throttled when the tab is in the background.' },
    { subtopicId: 'event-loop', text: 'What happens when you call JSON.parse on a deeply nested object — is it synchronous or does it block the event loop?', difficulty: 'expert', answer: 'JSON.parse is fully synchronous and executes on the main thread, so parsing a very large or deeply nested string will block the event loop for the duration of the parse. For huge payloads you should stream the parse or offload it to a worker to avoid UI jank or missed time-slice deadlines.' },
    { subtopicId: 'prototypes', text: 'What is the prototype chain and how does Object.create() let you build it?', difficulty: 'easy', answer: 'Every object has an internal [[Prototype]] link; property lookups walk up this chain until the property is found or null is reached. Object.create(proto) creates a new object with its [[Prototype]] set to proto, letting you explicitly define the chain without a constructor function.' },
    { subtopicId: 'prototypes', text: 'Explain the difference between __proto__ and prototype property on a constructor function.', difficulty: 'expert', answer: '__proto__ is the actual [[Prototype]] link on every object instance (the object it inherits from). prototype is a regular property on a function that becomes the __proto__ of objects created with new. They are different concepts: __proto__ is the runtime inheritance link, while prototype is the blueprint property on constructors.' },
    { subtopicId: 'prototypes', text: 'How does the class keyword relate to prototypal inheritance under the hood?', difficulty: 'medium', answer: 'ES6 class syntax is syntactic sugar over prototypal inheritance: a class constructor\'s prototype property is set as the __proto__ of instances, methods are placed on the prototype, and super delegates to the parent prototype via [[HomeObject]]. Under the hood it is still prototype-based delegation, just with cleaner syntax and mandatory new usage.' },
    { subtopicId: 'async', text: 'When would you use Promise.allSettled instead of Promise.all?', difficulty: 'medium', answer: 'Use Promise.allSettled when you want the result of every promise regardless of rejection, such as when each operation is independent and you want to report or retry failures without aborting the entire batch. Promise.all rejects immediately on the first failure, making it unsuitable when partial success is acceptable.' },
    { subtopicId: 'async', text: 'How would you implement a retry function that re-runs an async operation up to N times with exponential backoff?', difficulty: 'expert', answer: 'Wrap the call in a loop with a try/catch, incrementing a delay (e.g. 2^attempt * baseMs) on each failure before retrying. Use await new Promise(r => setTimeout(r, delay)) for the wait, and return the result on success or throw after exhausting attempts. Optionally add jitter to the delay to prevent thundering-herd retries.' },
    { subtopicId: 'async', text: 'What is the difference between for...of with async/await and Promise.all for concurrent execution?', difficulty: 'medium', answer: 'for...of with await runs promises sequentially, starting each only after the previous one settles. Promise.all starts all promises immediately and waits for all to settle, achieving true concurrency. Use for...of when order or rate-limiting matters; use Promise.all when independent tasks should run in parallel for speed.' },
    { subtopicId: 'async', text: 'How do you cancel a pending Promise, and what patterns exist for doing so?', difficulty: 'expert', answer: 'Promises themselves are not cancellable, but you can use an AbortController: pass signal to the async operation (e.g. fetch) and call controller.abort() to reject it. Another pattern is wrapping the promise with a race against a rejection triggered by an external flag, or using dedicated cancellation-aware libraries like p-cancelable.' },
    { subtopicId: 'modules', text: 'What is tree-shaking and how does ES module structure enable it?', difficulty: 'medium', answer: 'Tree-shaking is dead-code elimination that removes exports a bundle never imports. ES modules use static, declaration-level import/export syntax, which lets bundlers statically analyse dependency graphs and discard unused bindings at build time. CommonJS require is dynamic, making the same analysis infeasible.' },
    { subtopicId: 'modules', text: 'Why are side effects at the top level of a module a potential problem for tree-shaking?', difficulty: 'expert', answer: 'Bundlers cannot safely remove a module with top-level side effects because the effects (e.g. DOM manipulation, global mutations) may be relied upon. If a module only re-exports values and the bundler can prove no re-export is used, it can drop the module — but top-level code forces the bundler to keep the entire module to preserve observable behaviour.' },
    { subtopicId: 'error-handling', text: 'When would you create a custom error class instead of using a generic Error?', difficulty: 'medium', answer: 'Use a custom error class when callers need to distinguish between different failure modes programmatically, such as catching a ValidationError separately from a NetworkError. Custom errors also let you attach domain-specific properties (e.g. status codes, field names) and provide more meaningful stack traces for debugging.' },
    { subtopicId: 'error-handling', text: 'How does the error boundary pattern work in JavaScript without try-catch?', difficulty: 'medium', answer: 'In callback-based systems you propagate errors by passing them to a dedicated error-first callback (err, result), allowing a central handler at the top of the call chain. In promise chains, a single .catch() at the end catches any rejection. Both approaches centralize error handling without wrapping every call in try-catch.' },
    { subtopicId: 'types-coercion', text: 'What are the rules of abstract equality (==) in JavaScript, and why is strict equality (===) preferred?', difficulty: 'easy', answer: 'Abstract equality performs type coercion before comparing: booleans coerce to numbers, strings to numbers when compared to numbers, null equals only null or undefined, and objects are converted via valueOf/toString. Strict equality (===) skips coercion entirely, so "1" == 1 is true but "1" === 1 is false, making === the safer default to avoid surprising implicit conversions.' },
    { subtopicId: 'types-coercion', text: 'What happens when you add an object with a valueOf method to a number?', difficulty: 'expert', answer: 'The + operator triggers the ToPrimitive abstract operation, which calls the object\'s valueOf() method (if it returns a primitive) and uses that value for the addition. If valueOf does not return a primitive, toString is called next. You can therefore make 1 + { valueOf: () => 2 } evaluate to 3 by returning a number from valueOf.' },
  ],
}

