const NODEJS_SUBTOPICS: TopicSubtopics = {
  topicId: 'nodejs',
  subtopics: [
    { id: 'event-loop', label: 'Event Loop', keywords: ['event loop', 'libuv', 'callback', 'tick', 'phase', 'settimeout', 'setimmediate', 'process.nexttick'] },
    { id: 'streams', label: 'Streams', keywords: ['stream', 'readable', 'writable', 'transform', 'pipe', 'backpressure', 'chunk'] },
    { id: 'modules', label: 'Module System', keywords: ['require', 'import', 'commonjs', 'esm', 'module', 'exports', 'cjs'] },
    { id: 'async', label: 'Async Patterns', keywords: ['async', 'await', 'callback', 'promise', 'event emitter', 'stream'] },
    { id: 'filesystem', label: 'File System & IO', keywords: ['fs', 'file', 'directory', 'path', 'readfile', 'writefile', 'stream'] },
    { id: 'process', label: 'Process & OS', keywords: ['process', 'env', 'argv', 'cluster', 'worker', 'child_process', 'memory', 'cpu'] },
  ],
  questions: [
    { subtopicId: 'event-loop', text: 'What is the difference between process.nextTick() and setImmediate()?', difficulty: 'medium', answer: 'process.nextTick() queues a callback that runs immediately after the current operation completes, before the event loop continues. setImmediate() queues a callback that runs in the check phase of the next event loop iteration. In practice, nextTick callbacks always fire before setImmediate callbacks, which makes nextTick useful for ensuring a callback runs before any I/O or timer events.' },
    { subtopicId: 'event-loop', text: 'How does Node.js handle blocking operations, and what happens when you call a synchronous fs function in a request handler?', difficulty: 'medium', answer: 'Node.js runs JavaScript on a single-threaded event loop, so any synchronous blocking operation freezes the entire event loop and prevents all other requests from being processed. Calling a synchronous fs function like fs.readFileSync in a request handler blocks the thread until the file read completes, creating a bottleneck under concurrent load. Non-blocking alternatives like fs.promises or callbacks offload the I/O to libuv\'s thread pool, keeping the event loop free.' },
    { subtopicId: 'event-loop', text: 'What are the different phases of the Node.js event loop and in what order do they execute?', difficulty: 'expert', answer: 'The event loop executes in six phases in order: timers (setTimeout/setInterval callbacks), pending callbacks (I/O callbacks deferred to the next iteration), idle/prepare (internal), poll (retrieves new I/O events and executes I/O callbacks), check (setImmediate callbacks), and close callbacks (socket.on("close")). Between each phase, Node.js drains the microtask queue (Promise callbacks and process.nextTick callbacks), with nextTick running before Promise callbacks.' },
    { subtopicId: 'event-loop', text: 'When would you use worker_threads instead of child_process for CPU-bound work?', difficulty: 'expert', answer: 'Use worker_threads when you need to offload CPU-intensive computation without the overhead of spawning a separate process. Workers share memory via SharedArrayBuffer, have lower startup cost, and can transfer data with ArrayBuffer transfer instead of serialization. Use child_process when you need complete isolation, such as running untrusted code or a different executable, since each child process gets its own V8 instance and memory space.' },
    { subtopicId: 'streams', text: 'When would you use a Transform stream versus a simple async function?', difficulty: 'medium', answer: 'Use a Transform stream when you need to process data in chunks as it flows through, especially for large or infinite datasets where buffering everything in memory is impractical. Transform streams integrate with the pipe() ecosystem and handle backpressure automatically. A simple async function is sufficient when the input is small and can be fully buffered, or when the transformation does not need to be part of a streaming pipeline.' },
    { subtopicId: 'streams', text: 'Explain backpressure in Node.js streams and how pipe() handles it.', difficulty: 'expert', answer: 'Backpressure occurs when a readable stream produces data faster than the writable stream can consume it. Node.js streams use an internal buffer with a highWaterMark; when the buffer fills, the readable stream stops emitting data. pipe() automatically handles this by pausing the readable when the writable\'s write() returns false and resuming it via the drain event once the writable is ready for more data. This prevents unbounded memory growth in streaming pipelines.' },
    { subtopicId: 'streams', text: 'How do you convert a readable stream to a string or buffer?', difficulty: 'medium', answer: 'Use the stream/consumers module\'s text() or buffer() utilities, which accumulate stream chunks into a complete string or Buffer. You can also use the async iterable syntax with for await...of to collect chunks into an array and join them. For simple cases, stream.pipeline with a WritableStream can collect data, but stream/consumers is the most idiomatic approach in modern Node.js.' },
    { subtopicId: 'streams', text: 'What is the difference between objectMode streams and regular binary streams?', difficulty: 'medium', answer: 'Regular binary streams work with Buffers or strings where each chunk is a piece of binary data. objectMode streams accept arbitrary JavaScript objects as chunks, making them useful for pipeline stages that parse, filter, or transform structured data. ObjectMode streams do not support concatenation and their highWaterMark is measured in number of objects rather than bytes.' },
    { subtopicId: 'modules', text: 'Why does Node.js support both require and import, and what are the gotchas of mixing them?', difficulty: 'medium', answer: 'Node.js supports CommonJS (require) as its original module system and ESM (import) as the standardized JavaScript module system, maintaining backward compatibility. The main gotcha is that you cannot use require() inside a native ESM module, and using import in a CommonJS module only works with dynamic import(). Additionally, the two systems have different resolution algorithms and top-level this values, which can cause subtle bugs when mixing them in the same project.' },
    { subtopicId: 'modules', text: 'How does the __dirname variable work in ESM modules where it is not available?', difficulty: 'medium', answer: 'ESM modules do not have __dirname or __filename globals because the specification does not define them. You can derive the equivalent by using import.meta.url, which contains the module\'s file URL, then passing it to new URL(".", import.meta.url).pathname or using path.dirname(fileURLToPath(import.meta.url)) from the url module. This gives you the directory of the current module file.' },
    { subtopicId: 'modules', text: 'What is the purpose of the package.json "type": "module" field?', difficulty: 'easy', answer: 'The "type": "module" field tells Node.js to treat .js files in the package as ES modules by default instead of CommonJS. Without it, Node.js assumes .js files are CommonJS and you must use .mjs extension for ESM. Setting "type": "module" lets you use import/export syntax in .js files without renaming them, though you can still use .cjs for files that must remain CommonJS.' },
    { subtopicId: 'async', text: 'How would you handle errors in a long chain of async/await calls without repeating try-catch everywhere?', difficulty: 'medium', answer: 'Use a higher-order wrapper function that takes an async function and returns a new function that catches any rejection and forwards it to an error handler. Another approach is to use Promise.allSettled for parallel operations where partial failures are acceptable, or structure your code with a centralized error-handling middleware if you are in a framework like Express. You can also use a utility like .catch() at the end of a promise chain as a fallback.' },
    { subtopicId: 'async', text: 'What is the difference between an EventEmitter and a Promise for async patterns?', difficulty: 'medium', answer: 'A Promise represents a single eventual value or rejection and can only be settled once. An EventEmitter can emit zero, one, or many events over time and supports multiple listeners per event, making it suitable for ongoing streams of data like network connections or process signals. Promises are composable with then/catch/all, while EventEmitters require manual listener management and do not compose as cleanly.' },
    { subtopicId: 'async', text: 'When would you use the async iterator protocol (for await...of) over standard Promises?', difficulty: 'expert', answer: 'Use async iterators when you need to consume a sequence of values that arrive over time, such as lines from a readable stream, paginated API results, or real-time data from a WebSocket. Unlike Promise.all which resolves all values at once, for await...of processes each value sequentially as it becomes available, providing natural backpressure. This is ideal for streaming data where you cannot or should not buffer everything in memory first.' },
    { subtopicId: 'filesystem', text: 'When would you use the synchronous fs methods versus the callback or Promise-based ones?', difficulty: 'easy', answer: 'Synchronous fs methods are acceptable for short-lived scripts, CLI tools, or startup-time file reads where blocking does not matter. In a server or any concurrent application, always use async methods (callbacks, promises, or async iterators) to avoid blocking the event loop and degrading throughput. The sync variants are convenient but fundamentally incompatible with Node.js\'s non-blocking design for request handling.' },
    { subtopicId: 'filesystem', text: 'How does the fs.createReadStream approach differ from fs.readFile for large files?', difficulty: 'medium', answer: 'fs.readFile loads the entire file into memory before returning it, which can cause high memory usage or crashes with large files. fs.createReadStream processes the file in chunks via a readable stream, keeping memory usage constant regardless of file size. For large files, streaming is strongly preferred because it avoids buffering the entire content and integrates naturally with Node.js\'s backpressure-aware stream pipeline.' },
    { subtopicId: 'filesystem', text: 'What is the purpose of fs.promises and how does it differ from util.promisify?', difficulty: 'medium', answer: 'fs.promises provides a promise-based API for the fs module that avoids callback wrapping entirely, with methods like fs.promises.readFile returning native Promises. util.promisify converts individual callback-based functions into promise-returning ones at runtime. fs.promises is the officially supported approach with consistent error handling and slightly better performance, while promisify is a general utility for any callback-based function including third-party libraries.' },
    { subtopicId: 'process', text: 'When would you use the cluster module versus worker_threads?', difficulty: 'expert', answer: 'Use cluster to scale a network server across multiple CPU cores, where each worker runs an independent instance of the server and shares the listening port. Cluster workers are separate Node.js processes with isolated memory. Use worker_threads for CPU-intensive computations within the same process, where you need shared memory via SharedArrayBuffer or want lower overhead than forking a full process. Cluster is for horizontal scaling of I/O; worker_threads are for parallelizing compute.' },
    { subtopicId: 'process', text: 'How do you handle unhandled promise rejections in a Node.js process?', difficulty: 'medium', answer: 'Listen for the unhandledRejection event on the process object to log or report rejections that were not caught with .catch() or a try-catch block. In recent Node.js versions (15+), unhandled rejections terminate the process by default to prevent silent failures. Always ensure every promise chain has error handling, and use process.on("unhandledRejection", handler) as a safety net for debugging, not as a substitute for proper error handling.' },
    { subtopicId: 'process', text: 'What environment variables should never be logged and why?', difficulty: 'easy', answer: 'Secrets like database passwords, API keys, JWT signing secrets, OAuth client secrets, and private keys should never be logged because log output is often stored in centralized logging systems accessible to multiple team members and can be exposed in breach scenarios. Logging secrets also risks inclusion in error monitoring services, CI/CD output, or accidentally committed .env files, creating serious security vulnerabilities.' },
  ],
}

