const EXPRESS_SUBTOPICS: TopicSubtopics = {
  topicId: 'express',
  subtopics: [
    { id: 'routing', label: 'Routing', keywords: ['route', 'router', 'get', 'post', 'put', 'delete', 'params', 'query', 'route matching'] },
    { id: 'middleware', label: 'Middleware', keywords: ['middleware', 'next', 'app.use', 'router.use', 'error middleware', 'apply'] },
    { id: 'error-handling', label: 'Error Handling', keywords: ['error', 'next(err)', 'error middleware', 'unhandled', 'async error'] },
    { id: 'rest', label: 'REST API Design', keywords: ['rest', 'resource', 'crud', 'status code', 'json', 'api', 'endpoint'] },
    { id: 'security', label: 'Security', keywords: ['helmet', 'cors', 'csrf', 'xss', 'sanitization', 'rate limit', 'authentication'] },
  ],
  questions: [
    { subtopicId: 'routing', text: 'How does Express match route parameters and when would you use a regex in a route path?', difficulty: 'medium', answer: 'Express matches named parameters like :id by capturing the URL segment into req.params. You would use a regex in a route path when you need precise control over what characters are allowed, such as restricting an id parameter to digits only with /^\\d+$/, which prevents the route from matching non-numeric paths.' },
    { subtopicId: 'routing', text: 'What is the difference between req.params, req.query, and req.body?', difficulty: 'easy', answer: 'req.params contains named route parameters from the URL path (e.g., /users/:id). req.query contains the parsed query string from the URL (e.g., ?page=1). req.body contains the parsed request body, which requires body-parsing middleware like express.json() to populate.' },
    { subtopicId: 'routing', text: 'When would you use Router-level middleware versus application-level middleware?', difficulty: 'medium', answer: 'Use Router-level middleware when the logic should only apply to a specific subset of routes, such as authentication checks for a particular API group. Use application-level middleware with app.use() when the logic must run on every request, such as logging, CORS headers, or global error handling.' },
    { subtopicId: 'routing', text: 'How do you version an API using Express routing?', difficulty: 'medium', answer: 'Create separate Router instances for each API version (e.g., routerV1 and routerV2) and mount them on versioned paths like /api/v1 and /api/v2. This lets you evolve endpoints independently while keeping the codebase organized, and you can deprecate an older router when it reaches end-of-life.' },
    { subtopicId: 'middleware', text: 'Explain the middleware execution order. What happens if a middleware forgets to call next()?', difficulty: 'easy', answer: 'Express executes middleware in the order they are registered, forming a chain where each middleware calls next() to pass control to the next one. If a middleware forgets to call next() and does not send a response, the request will hang until it times out because Express has no way to proceed down the chain.' },
    { subtopicId: 'middleware', text: 'How would you write middleware that handles both JSON and form-urlencoded bodies?', difficulty: 'medium', answer: 'Register two separate body-parsing middleware in sequence: express.json() for application/json and express.urlencoded({ extended: true }) for application/x-www-form-urlencoded. Express checks the Content-Type header and each parser only processes requests matching its content type, so both can coexist safely.' },
    { subtopicId: 'middleware', text: 'When would you use app.use(path, middleware) versus applying middleware inside a router?', difficulty: 'medium', answer: 'Use app.use(path, middleware) when you want to scope middleware to a URL prefix globally, such as /api requiring authentication. Use middleware inside a router when it should only apply to that specific group of routes, which keeps concerns encapsulated and avoids accidentally affecting unrelated endpoints.' },
    { subtopicId: 'middleware', text: 'How do you create middleware that runs only for specific HTTP methods?', difficulty: 'medium', answer: 'Use the app.METHOD() or router.METHOD() helpers (e.g., app.get(), router.post()) to define route-specific handlers, or check req.method inside a generic middleware and call next() early if the method does not match. Another pattern is writing a factory function like requireMethod("POST") that returns a middleware filtering by method.' },
    { subtopicId: 'error-handling', text: 'How do you handle async errors in Express 4 versus Express 5?', difficulty: 'medium', answer: 'In Express 4, async errors thrown in route handlers are not caught automatically, so you must wrap handlers in try-catch and call next(err) manually or use a wrapper like express-async-errors. Express 5 natively catches rejected promises from async route handlers and forwards them to the error handler without any wrapper.' },
    { subtopicId: 'error-handling', text: 'What is the purpose of the four-argument error handler (err, req, res, next)?', difficulty: 'easy', answer: 'The four-argument signature tells Express this is an error-handling middleware, so it is invoked only when next(err) is called or an error is thrown. Express distinguishes error handlers from regular middleware by checking if the function has exactly four parameters, and it uses this to catch and respond to any errors that propagate through the middleware chain.' },
    { subtopicId: 'error-handling', text: 'How do you propagate errors from nested async functions to the Express error handler?', difficulty: 'expert', answer: 'Any unhandled promise rejection from a nested async call must bubble up to the route handler, which then calls next(err). In Express 4, you need to catch at every async layer or use a wrapper. In Express 5, returning or awaiting the nested async call automatically forwards rejections to the error handler, eliminating the need for manual propagation at each level.' },
    { subtopicId: 'error-handling', text: 'When would you throw an error versus sending an error response directly?', difficulty: 'medium', answer: 'Throw an error (or call next(err)) when the error should be handled centrally by an error-handling middleware for consistent formatting, logging, or status-code mapping. Send a response directly with res.status().json() when the error is specific to that route and you want to return a tailored response without involving the global error handler.' },
    { subtopicId: 'rest', text: 'When would you return 201 vs 200 for a successful POST request?', difficulty: 'easy', answer: 'Return 201 Created when the POST request creates a new resource, as it communicates that something was born on the server and should include a Location header pointing to the new resource. Return 200 OK when the POST triggers an action that does not create a resource, such as sending an email or processing a payment.' },
    { subtopicId: 'rest', text: 'How do you implement pagination in a REST API — offset-based vs cursor-based?', difficulty: 'medium', answer: 'Offset-based pagination uses ?page=2&limit=20 to skip a fixed number of records, which is simple but becomes slow and inconsistent when data mutates between requests. Cursor-based pagination uses an opaque cursor (often an ID or timestamp) in ?cursor=xyz to fetch the next page, which is more efficient for large datasets and handles inserts and deletes gracefully without skipping or duplicating records.' },
    { subtopicId: 'rest', text: 'What HTTP status codes should you use for authentication and authorization failures?', difficulty: 'medium', answer: 'Use 401 Unauthorized when the user is not authenticated or their token is missing/invalid, and include a WWW-Authenticate header describing the required scheme. Use 403 Forbidden when the user is authenticated but lacks permission to access the resource. Returning the correct code lets clients distinguish between needing to log in versus being denied access.' },
    { subtopicId: 'rest', text: 'How do you handle partial updates — PUT vs PATCH semantics?', difficulty: 'medium', answer: 'PUT replaces the entire resource with the submitted representation, so you must send all fields even if only one changed. PATCH applies a partial modification, letting you send only the fields that need updating. Use PUT for full replaces and PATCH for partial updates, and consider JSON Merge Patch or JSON Patch as the body format for PATCH requests.' },
    { subtopicId: 'security', text: 'What does the helmet middleware do, and which headers does it set?', difficulty: 'medium', answer: 'Helmet sets several HTTP security headers to protect against common vulnerabilities, including Content-Security-Policy, X-Content-Type-Options (nosniff), X-Frame-Options (DENY), Strict-Transport-Security (HSTS), and X-XSS-Protection. It acts as a collection of middleware that hardens your Express app against clickjacking, MIME sniffing, and other attacks with sensible defaults.' },
    { subtopicId: 'security', text: 'How do you implement rate limiting in Express and why is it important?', difficulty: 'medium', answer: 'Use a library like express-rate-limit, which tracks requests per IP or API key using an in-memory store or Redis, and returns 429 Too Many Requests when the limit is exceeded. Rate limiting is critical for preventing brute-force attacks, DDoS, and API abuse, and it protects your server resources by capping how many requests a client can make in a given time window.' },
    { subtopicId: 'security', text: 'What is the difference between CORS and CSRF, and how do you handle each in Express?', difficulty: 'medium', answer: 'CORS (Cross-Origin Resource Sharing) controls which external domains can make requests to your API from a browser, handled by the cors middleware setting Access-Control headers. CSRF (Cross-Site Request Forgery) tricks an authenticated user into submitting unwanted requests, prevented with anti-CSRF tokens or SameSite cookie attributes. CORS is about restricting origins; CSRF is about verifying intent.' },
    { subtopicId: 'security', text: 'When would you use HTTP-only cookies instead of Authorization headers for tokens?', difficulty: 'expert', answer: 'Use HTTP-only cookies for tokens when you want automatic browser-managed transport without exposing the token to JavaScript, which mitigates XSS-based token theft. Authorization headers give the client explicit control and work well for SPAs and mobile apps but require manual storage and cannot be automatically sent by the browser. HTTP-only cookies are ideal for server-rendered apps where CSRF protection via SameSite cookies is acceptable.' },
  ],
}

// ── JWT & Auth ──────────────────────────────────────────────────────────────

const JWT_SUBTOPICS: TopicSubtopics = {
  topicId: 'jwt',
  subtopics: [
    { id: 'token-basics', label: 'Token Basics', keywords: ['jwt', 'token', 'header', 'payload', 'signature', 'base64', 'claim'] },
    { id: 'sessions', label: 'Sessions vs Tokens', keywords: ['session', 'cookie', 'token', 'stateless', 'stateful', 'storage'] },
    { id: 'refresh', label: 'Refresh Flows', keywords: ['refresh token', 'access token', 'rotation', 'expiry', 'silent refresh'] },
    { id: 'signing', label: 'Signing & Verification', keywords: ['sign', 'verify', 'hmac', 'rsa', 'secret', 'public key', 'private key', 'algorithm'] },
    { id: 'security', label: 'Security Considerations', keywords: ['xss', 'csrf', 'httponly', 'secure', 'samesite', 'replay', 'exposure', 'storage'] },
  ],
  questions: [
    { subtopicId: 'token-basics', text: 'What are the three parts of a JWT and what does each contain?', difficulty: 'easy', answer: 'A JWT consists of three Base64URL-encoded segments separated by dots: the header (algorithm and token type), the payload (claims such as subject, expiry, and custom data), and the signature (used to verify the token was issued by a trusted party and has not been tampered with).' },
    { subtopicId: 'token-basics', text: 'Why is a JWT payload not encrypted — and is that a security problem?', difficulty: 'medium', answer: 'A JWT payload is only Base64URL-encoded, not encrypted, so anyone with the token can decode and read its contents. This is by design — JWTs are meant for verifiable claims, not secrecy. It becomes a security problem only if sensitive data (like passwords or PII) is placed in the payload. If confidentiality is required, use JWE (JSON Web Encryption) or keep secrets out of the token entirely.' },
    { subtopicId: 'token-basics', text: 'How do you read the claims in a JWT without verifying the signature?', difficulty: 'easy', answer: 'Split the token on the dot separator, Base64URL-decode the second segment (the payload), and parse the resulting JSON. Libraries like jose or jwt.io provide helpers for this. The data is readable without verification, but you should never trust it for authorization until the signature has been validated against the expected key.' },
    { subtopicId: 'token-basics', text: 'What is the difference between registered, public, and private JWT claims?', difficulty: 'medium', answer: 'Registered claims (like iss, sub, exp, aud) are predefined by the JWT/RFC 7519 specification and carry standard meanings. Public claims are defined by consumers using collision-resistant names, typically as URIs. Private claims are custom agreements between issuer and consumer, using arbitrary names, but must not conflict with registered or public claim names.' },
    { subtopicId: 'sessions', text: 'When would you choose server-side sessions over JWTs, and vice versa?', difficulty: 'medium', answer: 'Choose server-side sessions when you need immediate revocation (e.g., admin can invalidate a session instantly), when storing large amounts of per-user state, or when working with traditional server-rendered apps. Choose JWTs for stateless microservices, SPAs, or mobile apps where the token must travel across domains without shared server-side storage.' },
    { subtopicId: 'sessions', text: 'How do you implement session fixation protection when using server-side sessions?', difficulty: 'expert', answer: 'Regenerate the session ID after a successful authentication by calling session regeneration (e.g., req.session.regenerate() in Express) so the old session ID becomes invalid. Also invalidate any existing session cookie on the client by setting a new cookie with a fresh value. Additionally, bind the session to metadata like IP address and user-agent to detect session misuse.' },
    { subtopicId: 'sessions', text: 'What are the scalability trade-offs between session-based and token-based auth?', difficulty: 'medium', answer: 'Session-based auth requires shared or sticky server-side storage (like Redis or a database) so any server instance can validate a session, which adds latency and infrastructure complexity. Token-based auth is stateless — any server with the signing key can validate a token — making horizontal scaling simpler, but revocation and centralized state changes become harder since you cannot easily invalidate a token before its expiry.' },
    { subtopicId: 'sessions', text: 'When would you store a session in Redis versus a database?', difficulty: 'medium', answer: 'Use Redis for high-throughput, low-latency session stores where sub-millisecond reads are critical, such as real-time apps or high-traffic web services. Use a database (like PostgreSQL or MongoDB) when you need durability, complex querying of session data, or when your infrastructure already has a database and adding Redis would be overhead. Redis is faster but volatile without persistence; databases are slower but more durable.' },
    { subtopicId: 'refresh', text: 'Explain the access token / refresh token pattern. Why not just use a long-lived token?', difficulty: 'medium', answer: 'Access tokens are short-lived (e.g., 15 minutes) to limit the window of exposure if stolen, while refresh tokens are long-lived and used to silently obtain new access tokens. Using only a long-lived token means a stolen token grants indefinite access with no automatic expiration. The two-token pattern lets you keep the user logged in while minimizing the risk window for compromised access tokens.' },
    { subtopicId: 'refresh', text: 'How does token rotation protect against token theft, and what are its downsides?', difficulty: 'expert', answer: 'Token rotation issues a new refresh token with each use and invalidates the previous one, so a stolen token can only be used once before it becomes invalid. The downside is added complexity in handling race conditions (concurrent requests using the same token), the need for a token family tracking system, and legitimate users may be logged out if they have multiple devices using an old token simultaneously.' },
    { subtopicId: 'refresh', text: 'How do you handle the scenario where a refresh token is used after it has been rotated?', difficulty: 'expert', answer: 'When a rotated refresh token is reused, it indicates potential token theft — the legitimate client already used it and received a new token. The server should detect this via token family tracking, revoke the entire token family (all tokens issued from the same original refresh token), and optionally notify the user. This prevents the attacker from continuing to use the stolen token while forcing a re-authentication.' },
    { subtopicId: 'refresh', text: 'What is the sliding window expiration pattern for refresh tokens?', difficulty: 'medium', answer: 'A sliding window refresh token extends its expiry each time it is used, resetting the countdown from the current moment. This keeps the session alive as long as the user is active, and the token expires after a period of inactivity. It is simpler than absolute expiry (where the token has a fixed hard deadline) but requires storing the last-used timestamp to calculate the remaining validity window.' },
    { subtopicId: 'signing', text: 'What is the difference between HMAC and RSA signing for JWTs?', difficulty: 'medium', answer: 'HMAC uses a single shared secret to both create and verify the signature, so the same party that issues the token also validates it. RSA uses an asymmetric key pair: a private key signs the token and a public key verifies it, allowing any party with the public key to validate tokens without the ability to issue new ones. HMAC is faster; RSA enables distributed verification without sharing a secret.' },
    { subtopicId: 'signing', text: 'When would you use asymmetric (RS256) versus symmetric (HS256) signing?', difficulty: 'medium', answer: 'Use RS256 when multiple services need to verify tokens independently without sharing a secret (e.g., in microservices or third-party integrations). Use HS256 when a single issuer both creates and verifies tokens in a controlled environment, such as a monolith. RS256 is preferred for public-facing APIs where sharing a secret is a security risk; HS256 is simpler and faster for internal use cases.' },
    { subtopicId: 'signing', text: 'How does JWK (JSON Web Key) simplify key rotation for JWT verification?', difficulty: 'expert', answer: 'JWK provides a standard JSON format for publishing public keys with unique identifiers (kid), allowing services to fetch the correct key by ID from a JWKS endpoint (e.g., /.well-known/jwks.json). During key rotation, the issuer publishes a new key alongside the old one, giving verifiers time to migrate. Once the old key is removed, only the new key is accepted, enabling seamless rotation without downtime.' },
    { subtopicId: 'security', text: 'Where should you store JWTs to prevent XSS attacks, and what trade-off does that introduce?', difficulty: 'medium', answer: 'Store JWTs in an HttpOnly, Secure, SameSite=Strict cookie to prevent JavaScript access, which blocks XSS-based token theft. The trade-off is that you lose the ability to read the token client-side, making automatic token renewal and custom header injection harder. If you must read the token client-side, store it in memory (not localStorage) and accept the risk that XSS could still exfiltrate it.' },
    { subtopicId: 'security', text: 'What is the "none" algorithm attack and how do libraries defend against it?', difficulty: 'expert', answer: 'The "none" algorithm attack exploits JWTs where the header specifies algorithm: "none", meaning no signature is applied. An attacker can forge a token with arbitrary claims and the verifier would accept it if it does not explicitly reject the none algorithm. Secure libraries defend against this by refusing to accept the none algorithm unless it is explicitly allowed in the verification configuration, and by always requiring a valid signature.' },
    { subtopicId: 'security', text: 'How do you prevent JWT replay attacks in a microservices architecture?', difficulty: 'expert', answer: 'Prevent replay attacks by using short-lived access tokens (reducing the window of reuse), including a unique jti (JWT ID) claim and tracking used tokens in a revocation list or cache, implementing nonce-based mechanisms where each token can only be used once, and using mutual TLS or request signing at the transport layer to prevent token interception and reuse across services.' },
    { subtopicId: 'security', text: 'Why should you always validate the `iss` and `aud` claims on the server?', difficulty: 'medium', answer: 'The iss (issuer) claim confirms the token came from an expected authority, preventing tokens issued by a different service or environment from being accepted. The aud (audience) claim ensures the token was intended for your specific service, preventing a token meant for Service A from being replayed against Service B. Without validating both, your service is vulnerable to token confusion and cross-service replay attacks.' },
  ],
}

