const MONGODB_SUBTOPICS: TopicSubtopics = {
  topicId: 'mongodb',
  subtopics: [
    { id: 'documents', label: 'Document Design', keywords: ['document', 'schema', 'embed', 'reference', 'normalization', 'denormalization', 'bson'] },
    { id: 'indexes', label: 'Indexes', keywords: ['index', 'compound', 'unique', 'sparse', 'text', 'explain', 'scan'] },
    { id: 'aggregation', label: 'Aggregation Pipeline', keywords: ['aggregate', 'pipeline', 'match', 'group', 'lookup', 'project', 'unwind', 'sort'] },
    { id: 'crud', label: 'CRUD Operations', keywords: ['find', 'insert', 'update', 'delete', 'upsert', 'bulk', 'replace'] },
    { id: 'transactions', label: 'Transactions & Consistency', keywords: ['transaction', 'session', 'atomic', 'consistency', 'isolation', 'causally consistent'] },
  ],
  questions: [
    { subtopicId: 'documents', text: 'When would you embed a sub-document versus referencing another collection?', difficulty: 'easy', answer: 'Embed when the child data is always accessed alongside the parent, is bounded in size, and does not need independent queries. Reference when the child is large, unbounded, queried independently, or shared across multiple parents. Embedding gives you atomic reads and writes in a single document; referencing avoids unbounded document growth and duplication.' },
    { subtopicId: 'documents', text: 'How does the 16MB document size limit affect your schema design decisions?', difficulty: 'medium', answer: 'The 16MB BSON document limit forces you to avoid unbounded arrays or large binary fields that could grow without control. Use references and pagination instead of embedding thousands of sub-documents. GridFS is the standard workaround for storing files larger than 16MB. Schema design should anticipate worst-case growth, not just current data.' },
    { subtopicId: 'documents', text: 'What are the trade-offs between embedding arrays of sub-documents versus using a separate collection?', difficulty: 'medium', answer: 'Embedding arrays enables single-query reads and atomic updates but couples the data lifecycle and can cause document bloat. A separate collection allows independent querying, indexing, and growth but requires $lookup or multiple queries to reassemble the data. Choose embedding for tightly-coupled, bounded data; choose a separate collection for large, independent, or frequently queried data.' },
    { subtopicId: 'documents', text: 'When would you use references with $lookup instead of embedding for a one-to-many relationship?', difficulty: 'expert', answer: 'Use $lookup when the "many" side is large, independently queryable, or frequently updated, because embedding would cause document bloat and expensive updates. $lookup is also appropriate when the child documents are shared across multiple parent documents. The trade-off is query complexity and performance — $lookup is essentially a join and cannot use indexes as efficiently as embedded denormalization in a single document read.' },
    { subtopicId: 'indexes', text: 'Explain how a compound index supports a query that filters on both fields AND sorts on a third.', difficulty: 'medium', answer: 'A compound index can support a query that filters on prefix fields and sorts on the next field in the index key pattern, as long as all preceding fields are equality filters. For example, an index on { status: 1, category: 1, date: -1 } supports a query filtering on status and category while sorting by date. The ESR rule (Equality, Sort, Range) helps you order compound index fields optimally.' },
    { subtopicId: 'indexes', text: 'When would an index hurt performance instead of helping it?', difficulty: 'expert', answer: 'Indexes hurt performance when they are unused by queries, consume excessive storage and memory, or slow down write operations due to index maintenance overhead. Low-selectivity indexes on fields with few distinct values force the query planner to scan many index entries. Write-heavy workloads pay the cost of updating every index on every insert, update, and delete.' },
    { subtopicId: 'indexes', text: 'How do you decide which fields to include in a compound index?', difficulty: 'medium', answer: 'Start by analyzing your most frequent and critical queries using explain() to identify which fields appear in filters, sorts, and projections. Apply the ESR rule: Equality fields first, then Sort fields, then Range fields. A single well-designed compound index can serve multiple queries, but avoid over-indexing — each index adds write overhead and storage cost.' },
    { subtopicId: 'indexes', text: 'What is the difference between a sparse index and a partial index?', difficulty: 'medium', answer: 'A sparse index simply omits documents that lack the indexed field entirely. A partial index includes only documents that match a filter expression you define, giving you much more control over which documents are indexed. A partial index is more flexible and generally preferred — you can express conditions like "only index documents where status equals active" rather than just checking for field existence.' },
    { subtopicId: 'aggregation', text: 'Walk through a pipeline that calculates the average order value per customer.', difficulty: 'medium', answer: 'A typical pipeline would use $group with _id set to the customer ID, summing the order values with $sum and counting orders with $sum of 1, then a $project stage that divides the total by the count to compute the average. If orders live in a separate collection, start with $lookup to join them, then $unwind the joined array, and finally $group to aggregate per customer.' },
    { subtopicId: 'aggregation', text: 'How does $lookup differ from a SQL JOIN, and what are its performance implications?', difficulty: 'medium', answer: 'Unlike a SQL JOIN, $lookup only supports a left outer join and cannot do full joins, multiple join conditions, or join on non-equality predicates in a single stage. $lookup is executed as a nested loop or hash join internally, which can be expensive on large collections without an index on the foreign field. For best performance, ensure the foreign collection has an index on the field referenced by localField or foreignField.' },
    { subtopicId: 'aggregation', text: 'When would you use $facet to run multiple aggregations in a single pipeline?', difficulty: 'expert', answer: 'Use $facet when you need to produce multiple result sets from the same input documents in a single pass, such as computing different aggregations or applying different groupings simultaneously. This avoids re-reading the same collection multiple times and is ideal for dashboard-style queries where you need summary statistics, histograms, and top-N lists from one data source in one round trip.' },
    { subtopicId: 'aggregation', text: 'How do you handle null or missing fields in an aggregation pipeline?', difficulty: 'medium', answer: 'Missing fields and null values behave differently in MongoDB — a missing field is simply absent while a null field exists with the value null. Use $ifNull to provide defaults, $type to distinguish between them, and $addFields or $project with $cond to normalize both cases. Filter them early with $match if they should not participate in downstream calculations like $group or $sort.' },
    { subtopicId: 'crud', text: 'What is the difference between updateOne and replaceOne?', difficulty: 'easy', answer: 'updateOne applies update operators like $set, $inc, and $push to modify specific fields while leaving other fields untouched. replaceOne replaces the entire matching document with a new document, removing all existing fields except _id. Use updateOne when you want to change only certain fields; use replaceOne when you want to swap the entire document.' },
    { subtopicId: 'crud', text: 'When would you use upsert versus a separate find-and-insert pattern?', difficulty: 'medium', answer: 'Use upsert when you want to atomically insert a document if it does not exist or update it if it does, avoiding race conditions from a separate find-then-insert. Upsert is ideal for counters, event logs, and idempotent operations where you want exactly-once semantics. A separate find-and-insert is simpler for read-heavy logic but is not atomic and can lose writes under concurrency.' },
    { subtopicId: 'crud', text: 'How do you perform a bulk write operation efficiently in MongoDB?', difficulty: 'medium', answer: 'Use the bulkWrite() method, which batches multiple insertOne, updateOne, replaceOne, and deleteOne operations into a single network round trip. Ordered bulk writes execute operations sequentially and stop on error; unordered operations execute in parallel for better throughput. Bulk operations reduce network overhead and are significantly faster than issuing individual write commands in a loop.' },
    { subtopicId: 'crud', text: 'What is the difference between $set and $setOnInsert in an update operation?', difficulty: 'medium', answer: '$set assigns a value to a field on every update, whether the document already exists or is being inserted via upsert. $setOnInsert only sets the field when a new document is being inserted as part of an upsert — it has no effect on existing documents. Use $setOnInsert for fields like createdAt or default configuration that should only be set once on creation.' },
    { subtopicId: 'transactions', text: 'When do you need a MongoDB transaction versus relying on document-level atomicity?', difficulty: 'medium', answer: 'Document-level atomicity covers single-document operations, which are always atomic. You need a multi-document transaction when you must atomically modify documents across multiple collections or multiple documents in the same collection, such as transferring a balance between two accounts. Transactions are also needed when you need snapshot isolation across a series of reads and writes that must see a consistent view of the data.' },
    { subtopicId: 'transactions', text: 'How does causal consistency work in a MongoDB replica set?', difficulty: 'expert', answer: 'Causal consistency ensures that every client sees causally related operations in a consistent order, even if they run on different replica set members. It works by attaching a cluster time and operation time to each operation, and the server guarantees that a causally consistent session will not read stale data from before a previous write. You enable it by using a causally consistent session (causalConsistency: true) in your client session.' },
    { subtopicId: 'transactions', text: 'What performance impact do multi-document transactions have and when is that acceptable?', difficulty: 'medium', answer: 'Multi-document transactions acquire locks and write oplog entries for every operation, adding latency and reducing throughput compared to non-transactional writes. They can also cause transaction conflicts under high concurrency and require wiredTiger snapshot isolation overhead. They are acceptable when atomicity across multiple documents is a correctness requirement, such as financial transfers or order processing, where data integrity outweighs the performance cost.' },
  ],
}

// ── Registry ────────────────────────────────────────────────────────────────

export const TOPIC_SUBTOPICS: TopicSubtopics[] = [
  HTML_SUBTOPICS,
  CSS_SUBTOPICS,
  JS_SUBTOPICS,
  TS_SUBTOPICS,
  REACT_SUBTOPICS,
  NEXTJS_SUBTOPICS,
  NODEJS_SUBTOPICS,
  EXPRESS_SUBTOPICS,
  JWT_SUBTOPICS,
  MONGODB_SUBTOPICS,
]

/** Get subtopics and questions for a topic ID. Returns undefined if unknown. */
export function subtopicsForTopic(topicId: string): TopicSubtopics | undefined {
  return TOPIC_SUBTOPICS.find((t) => t.topicId === topicId)
}

/** Flat list of subtopic labels for a topic, used in the system instruction. */
export function subtopicLabels(topicId: string): string[] {
  return subtopicsForTopic(topicId)?.subtopics.map((s) => s.label) ?? []
}

/** All keywords for a topic, keyed by subtopic ID. Used for transcript analysis. */
export function subtopicKeywords(topicId: string): Record<string, string[]> {
  const entry = subtopicsForTopic(topicId)
  if (!entry) return {}
  const map: Record<string, string[]> = {}
  for (const st of entry.subtopics) map[st.id] = st.keywords
  return map
}

/**
 * Given a transcript and a topic, return the set of subtopic IDs that appear
 * to have been covered. Detection is keyword-based and intentionally loose —
 * the report LLM provides the nuanced per-subtopic assessment.
 */
export function detectCoveredSubtopics(
  topicId: string,
  transcript: { role: string; text: string }[],
): string[] {
  const keywords = subtopicKeywords(topicId)
  const covered: string[] = []
  const allText = transcript.map((t) => t.text).join(' ').toLowerCase()

  for (const [subId, kws] of Object.entries(keywords)) {
    const matched = kws.some((kw) => allText.includes(kw.toLowerCase()))
    if (matched) covered.push(subId)
  }
  return covered
}
